const email = $input.first().json;
const from = email.from?.text || email.from?.value?.[0]?.address || email.from || 'Unknown';
const subject = email.subject || '(без темы)';
const body = (email.text || email.textAsHtml || email.html || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 1500);
const date = email.date || new Date().toISOString();
const emailId = 'em_' + Date.now() + '_' + Math.random().toString(36).slice(2,8);

const store = $getWorkflowStaticData('global');
if (!store.emailBuffer) store.emailBuffer = [];

store.emailBuffer.push({ id: emailId, from, subject, body, date, collected: new Date().toISOString() });
if (store.emailBuffer.length > 200) store.emailBuffer = store.emailBuffer.slice(-200);

return [{ json: { buffered: true, bufferSize: store.emailBuffer.length } }];

const store = $getWorkflowStaticData('global');
const emails = store.emailBuffer || [];

if (!emails.length) {
  return [{ json: { skip: true, count: 0 } }];
}

// Slot detection by Yekaterinburg local hour (UTC+5)
const hourEkb = (new Date().getUTCHours() + 5) % 24;
const slot = hourEkb < 14 ? '🌅 Утренняя' : '🌇 Вечерняя';

// Save emails snapshot for context
if (!store.emails) store.emails = [];
for (const e of emails) {
  store.emails.unshift({ id: e.id, from: e.from, subject: e.subject, body: e.body, date: e.date, summary: '' });
}
if (store.emails.length > 100) store.emails = store.emails.slice(0, 100);

// Build list for GPT (compact)
const list = emails.map((e,i) => (i+1) + '. От: ' + e.from + '\n   Тема: ' + e.subject + '\n   Текст: ' + (e.body || '').slice(0, 400)).join('\n\n');

// Clear buffer
store.emailBuffer = [];

return [{ json: { skip: false, count: emails.length, slot, list } }];

const data = $input.first().json;
const systemPrompt = 'Ты почтовый ассистент Зевс. Тебе дают список писем за период. Сделай КРАТКУЮ сводку на русском:\n\nФормат:\n🔴 ВАЖНОЕ (если есть) — оплаты, коды, банки, договора, дедлайны. 1-2 строки на каждое с указанием отправителя.\n📬 ПО ДЕЛУ (если есть) — рабочая переписка, личное, ответы. Кратко.\n📭 ПРОЧЕЕ — рассылки, реклама, уведомления. Одной строкой: "N рассылок (Ozon, VK, и др.)".\n\nВ конце: "Всего писем: N". Никаких комментариев, только сводка. Максимум 15 строк.';

const userContent = 'Писем за период: ' + data.count + '.\n\n' + data.list;

const body = JSON.stringify({
  model: 'gpt-4o-mini',
  messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: userContent }],
  max_tokens: 800
});

return [{ json: { body, slot: data.slot, count: data.count } }];

