const e = $input.first().json;
const from = (e.from?.text || e.from?.value?.[0]?.address || e.from || '').toLowerCase();
if (!/(alfa|альфа)/i.test(from)) return [];

const subject = e.subject || '';
const rawHtml = e.html || '';
const fullBody = (e.text || e.textAsHtml || rawHtml.replace(/<[^>]+>/g, ' ')).replace(/\s+/g, ' ').trim();

const amountMatch = fullBody.match(/списана\s+сумма\s+([\d\s]+(?:[.,]\d{2})?)/i);
if (amountMatch) {
  const amount = parseFloat(amountMatch[1].replace(/\s/g, '').replace(',', '.'));
  const acctMatch = fullBody.match(/счёта\s+\*(\d{4})/i);
  const account = acctMatch ? acctMatch[1] : null;
  const dateMatch = fullBody.match(/от\s+(\d{2}\.\d{2}\.\d{2,4})/);
  const txDate = dateMatch ? dateMatch[1] : null;
  let isoDate = null;
  if (txDate) {
    const parts = txDate.split('.');
    const yyyy = parts[2].length === 2 ? '20' + parts[2] : parts[2];
    isoDate = yyyy + '-' + parts[1].padStart(2,'0') + '-' + parts[0].padStart(2,'0');
  }
  const monthKey = isoDate ? isoDate.slice(0,7) : new Date().toISOString().slice(0,7);

  let purpose = '';
  const purposeIdx = fullBody.indexOf('Назначение платежа:');
  if (purposeIdx > -1) {
    purpose = fullBody.slice(purposeIdx + 'Назначение платежа:'.length).trim();
    const cuts = ['Это сообщение', 'С уважением', 'Информация для клиентов', 'Это автоматическ'];
    for (const c of cuts) {
      const i = purpose.indexOf(c);
      if (i > -1) purpose = purpose.slice(0, i).trim();
    }
    purpose = purpose.slice(0, 500);
  }

  const mccMatch = fullBody.match(/MCC\s*(\d{3,4})/i);
  const mcc = mccMatch ? mccMatch[1] : null;

  const store = $getWorkflowStaticData('global');
  if (!store.alfaTx) store.alfaTx = [];
  const txId = 'tx_' + Date.now() + '_' + Math.random().toString(36).slice(2,5);
  const tx = { id: txId, type: 'spending', amount, account, txDate, isoDate, monthKey, purpose, mcc, subject };
  store.alfaTx.push(tx);
  if (store.alfaTx.length > 5000) store.alfaTx = store.alfaTx.slice(-5000);

  return [{ json: Object.assign({ parsed: true }, tx) }];
}

return [{ json: { parsed: false, subject, body: fullBody.slice(0, 1500) } }];
